// Format the digest content
const windowData = items[0].json;
const articles = items[1].json.results[0];
const clusters = items[1].json.results[1];
const tasks = items[1].json.results[2];

const formatTime = (date) => {
  const d = new Date(date);
  return d.toLocaleString('en-US', { 
    hour: 'numeric', 
    hour12: true 
  });
};

const periodName = () => {
  const hour = new Date(windowData.start_time).getHours();
  if (hour === 22) return 'Evening';
  if (hour === 6) return 'Morning';
  return 'Afternoon';
};

// Build email content
let emailHtml = `
<h1>RSS Intelligence Digest - ${periodName()}</h1>
<p>${new Date().toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}</p>

<h2>Executive Summary</h2>
<ul>
  <li>Articles analyzed: <strong>${windowData.article_count}</strong></li>
  <li>Key insights extracted: <strong>${windowData.note_count}</strong></li>
  <li>Actionable tasks identified: <strong>${windowData.task_count || 0}</strong></li>
  <li>Time period: ${formatTime(windowData.start_time)} - ${formatTime(windowData.end_time)}</li>
</ul>
`;

// Trending topics
if (clusters && clusters.length > 0) {
  emailHtml += '<h2>Trending Topics</h2>';
  clusters.slice(0, 5).forEach(cluster => {
    emailHtml += `<h3>${cluster.cluster} (${cluster.count} articles)</h3>`;
    emailHtml += `<p>Average relevance score: ${cluster.avg_score.toFixed(1)}</p>`;
  });
}

// Top articles
emailHtml += '<h2>Key Insights</h2>';
articles.slice(0, 10).forEach((article, i) => {
  emailHtml += `
    <div style="margin-bottom: 20px; padding: 15px; background: #f5f5f5; border-left: 4px solid #2196F3;">
      <h3>${i + 1}. ${article.title}</h3>
      <p><strong>Score:</strong> ${article.score.toFixed(1)} | <strong>Topic:</strong> ${article.cluster || 'General'}</p>
      ${article.summary ? `<p>${article.summary}</p>` : ''}
      <p><a href="${article.url}">Read more →</a></p>
    </div>
  `;
});

// Actionable tasks
if (tasks && tasks.length > 0) {
  emailHtml += '<h2>Actionable Tasks</h2>';

  const tasksByPriority = tasks.reduce((acc, task) => {
    if (!acc[task.priority]) acc[task.priority] = [];
    acc[task.priority].push(task);
    return acc;
  }, {});

  ['critical', 'high', 'medium', 'low'].forEach(priority => {
    if (tasksByPriority[priority]) {
      emailHtml += `<h3>Priority: ${priority.toUpperCase()}</h3><ul>`;
      tasksByPriority[priority].forEach(task => {
        emailHtml += `<li>${task.task_description} <em>(from: ${task.source_article})</em></li>`;
      });
      emailHtml += '</ul>';
    }
  });
}

emailHtml += `
<hr>
<p style="color: #666; font-size: 0.9em;">
  Next digest: ${formatTime(new Date(windowData.end_time).getTime() + 8 * 60 * 60 * 1000)}<br>
  Powered by n8n RSS Intelligence System
</p>
`;

// Also create markdown version
let markdown = `# RSS Intelligence Digest - ${periodName()}\n\n`;
markdown += `Date: ${new Date().toLocaleDateString()}\n\n`;
markdown += `## Summary\n- Articles: ${windowData.article_count}\n`;
markdown += `- Insights: ${windowData.note_count}\n`;
markdown += `- Tasks: ${windowData.task_count || 0}\n\n`;

// Add articles to markdown
markdown += '## Key Articles\n\n';
articles.slice(0, 10).forEach(article => {
  markdown += `### ${article.title}\n`;
  markdown += `- Score: ${article.score.toFixed(1)}\n`;
  markdown += `- [Link](${article.url})\n\n`;
});

return [
  {
    json: {
      emailHtml,
      markdown,
      subject: `RSS Digest: ${periodName()} - ${windowData.article_count} articles, ${windowData.task_count || 0} tasks`,
      windowId: windowData.window_id
    }
  }
];
